class Solution:
    def minimumTotalPrice(self, n, edges, price, trips):
        import sys
        sys.setrecursionlimit(20000)
        graph = [[] for _ in range(n)]
        for a, b in edges:
            graph[a].append(b)
            graph[b].append(a)
        cnt = [0] * n
        def find_path(node, target, parent, path, visited):
            path.append(node)
            if node == target:
                return True
            visited.add(node)
            for nb in graph[node]:
                if nb not in visited:
                    if find_path(nb, target, node, path, visited):
                        return True
            path.pop()
            return False
        for start, end in trips:
            path = []
            find_path(start, end, -1, path, set())
            for node in path:
                cnt[node] += 1
        base = sum(c * p for c, p in zip(cnt, price))
        memo = {}
        def dp(node, parent, halved_parent):
            key = (node, parent, halved_parent)
            if key in memo:
                return memo[key]
            best_skip = 0
            for nb in graph[node]:
                if nb == parent:
                    continue
                best_skip += dp(nb, node, False)
            result = best_skip
            if not halved_parent:
                take = cnt[node] * price[node] // 2
                for nb in graph[node]:
                    if nb == parent:
                        continue
                    take += dp(nb, node, True)
                result = max(result, take)
            memo[key] = result
            return result
        return base - dp(0, -1, False)

