        cnt = [0] * n
        for start, end in trips:
            parent = [-1] * n
            visited = [False] * n
            visited[start] = True
            queue = [start]
            head = 0
            while head < len(queue):
                node = queue[head]
                head += 1
                if node == end:
                    break
                for nb in graph[node]:
                    if not visited[nb]:
                        visited[nb] = True
                        parent[nb] = node
                        queue.append(nb)
            node = end
            while True:
                cnt[node] += 1
                if node == start:
                    break
                node = parent[node]
        base = sum(c * p for c, p in zip(cnt, price))
        take = [0] * n
        skip = [0] * n
        parent = [-1] * n
        visited = [False] * n
        visited[0] = True
        order = [0]
        stack = [0]
        while stack:
            node = stack.pop()
            for nb in graph[node]:
                if not visited[nb]:
                    visited[nb] = True
                    parent[nb] = node
                    order.append(nb)
                    stack.append(nb)
        for node in reversed(order):
            t = cnt[node] * price[node] // 2
            s = 0
            for nb in graph[node]:
                if nb == parent[node]:
                    continue
                t += skip[nb]
                s += max(take[nb], skip[nb])
            take[node] = t
            skip[node] = s
        return base - max(take[0], skip[0])

