var minimumTotalPrice = function(n, edges, price, trips) {
    const graph = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        graph[a].push(b);
        graph[b].push(a);
    }
    const cnt = new Array(n).fill(0);
    for (const [start, end] of trips) {
        const parent = new Array(n).fill(-1);
        const visited = new Array(n).fill(false);
        visited[start] = true;
        const queue = [start];
        let head = 0;
        while (head < queue.length) {
            const node = queue[head++];
            if (node === end) break;
            for (const nb of graph[node]) {
                if (!visited[nb]) {
                    visited[nb] = true;
                    parent[nb] = node;
                    queue.push(nb);
                }
            }
        }
        let node = end;
        while (true) {
            cnt[node]++;
            if (node === start) break;
            node = parent[node];
        }
    }
    let base = 0;
    for (let i = 0; i < n; i++) base += cnt[i] * price[i];
    const take = new Array(n).fill(0);
    const skip = new Array(n).fill(0);
    const parent = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const order = [0];
    const stack = [0];
    while (stack.length) {
        const node = stack.pop();
        for (const nb of graph[node]) {
            if (!visited[nb]) {
                visited[nb] = true;
                parent[nb] = node;
                order.push(nb);
                stack.push(nb);
            }
        }
    }
    for (let i = order.length - 1; i >= 0; i--) {
        const node = order[i];
        let t = Math.floor((cnt[node] * price[node]) / 2);
        let s = 0;
        for (const nb of graph[node]) {
            if (nb === parent[node]) continue;
            t += skip[nb];
            s += Math.max(take[nb], skip[nb]);
        }
        take[node] = t;
        skip[node] = s;
    }
    return base - Math.max(take[0], skip[0]);
};
